echo "# stub" > "$CML_DOCS/traditional-ml/tutorials/hyperparameter-tuning/notebooks/parent-child-runs-ipynb.md"
echo "# stub" > "$CML_DOCS/traditional-ml/tutorials/creating-custom-pyfunc/notebooks/basic-pyfunc-ipynb.md"
echo "# stub" > "$CML_DOCS/traditional-ml/tutorials/creating-custom-pyfunc/notebooks/introduction-ipynb.md"
echo "# stub" > "$CML_DOCS/traditional-ml/tutorials/creating-custom-pyfunc/notebooks/override-predict-ipynb.md"
echo "# stub" > "$CML_DOCS/traditional-ml/tutorials/serving-multiple-models-with-pyfunc/notebooks/MME_Tutorial-ipynb.md"
echo "# stub" > "$CML_DOCS/deep-learning/transformers/tutorials/conversational/conversational-model-ipynb.md"
echo "# stub" > "$CML_DOCS/deep-learning/transformers/tutorials/conversational/pyfunc-chat-model-ipynb.md"
echo "# stub" > "$CML_DOCS/deep-learning/transformers/tutorials/fine-tuning/transformers-fine-tuning-ipynb.md"
echo "# stub" > "$CML_DOCS/deep-learning/transformers/tutorials/fine-tuning/transformers-peft-ipynb.md"
echo "# stub" > "$CML_DOCS/deep-learning/transformers/tutorials/audio-transcription/whisper-ipynb.md"
echo "# stub" > "$CML_DOCS/deep-learning/transformers/tutorials/prompt-templating/prompt-templating-ipynb.md"
echo "# stub" > "$CML_DOCS/deep-learning/transformers/tutorials/text-generation/text-generation-ipynb.md"
echo "# stub" > "$CML_DOCS/deep-learning/transformers/tutorials/translation/component-translation-ipynb.md"
echo "# stub" > "$CML_DOCS/deep-learning/sentence-transformers/tutorials/quickstart/sentence-transformers-quickstart-ipynb.md"
echo "# stub" > "$CML_DOCS/deep-learning/sentence-transformers/tutorials/semantic-similarity/semantic-similarity-sentence-transformers-ipynb.md"
echo "# stub" > "$CML_DOCS/deep-learning/sentence-transformers/tutorials/semantic-search/semantic-search-sentence-transformers-ipynb.md"
echo "# stub" > "$CML_DOCS/deep-learning/sentence-transformers/tutorials/paraphrase-mining/paraphrase-mining-sentence-transformers-ipynb.md"

# Additional stubs for redirect targets (without -ipynb suffix).
# docusaurus.config.ts has @docusaurus/plugin-client-redirects entries pointing FROM old paths
# TO these non-ipynb paths. The redirect targets must exist as actual pages.

# GenAI redirect targets
echo "# stub" > "$GENAI_DOCS/flavors/dspy/notebooks/dspy_quickstart.md"
echo "# stub" > "$GENAI_DOCS/flavors/langchain/notebooks/langchain-quickstart.md"
# langchain-retriever page has a cross-link to a specific section anchor in the source docs.
# Include the heading so the anchor exists in the stub and doesn't break the build.
printf -- '# stub\n\n## Establishing RetrievalQA Chain and Logging with MLflow\n' > "$GENAI_DOCS/flavors/langchain/notebooks/langchain-retriever.md"
echo "# stub" > "$GENAI_DOCS/flavors/llama-index/notebooks/llama_index_quickstart.md"
echo "# stub" > "$GENAI_DOCS/flavors/llama-index/notebooks/llama_index_workflow_tutorial.md"
