mkdir -p "$CML_DOCS/model/notebooks"
echo "# stub" > "$CML_DOCS/model/notebooks/signature_examples.md"
# eval-monitor quickstart page links to this notebook page
mkdir -p "$GENAI_DOCS/eval-monitor/notebooks"
echo "# stub" > "$GENAI_DOCS/eval-monitor/notebooks/quickstart-eval.md"
echo "# stub" > "$CML_DOCS/traditional-ml/tutorials/creating-custom-pyfunc/notebooks/basic-pyfunc.md"
echo "# stub" > "$CML_DOCS/traditional-ml/tutorials/creating-custom-pyfunc/notebooks/introduction.md"
echo "# stub" > "$CML_DOCS/traditional-ml/tutorials/creating-custom-pyfunc/notebooks/override-predict.md"
echo "# stub" > "$CML_DOCS/traditional-ml/tutorials/hyperparameter-tuning/notebooks/hyperparameter-tuning-with-child-runs.md"
echo "# stub" > "$CML_DOCS/traditional-ml/tutorials/hyperparameter-tuning/notebooks/logging-plots-in-mlflow.md"
echo "# stub" > "$CML_DOCS/traditional-ml/tutorials/hyperparameter-tuning/notebooks/parent-child-runs.md"
echo "# stub" > "$CML_DOCS/traditional-ml/tutorials/serving-multiple-models-with-pyfunc/notebooks/MME_Tutorial.md"
echo "# stub" > "$CML_DOCS/deep-learning/transformers/tutorials/conversational/conversational-model.md"
echo "# stub" > "$CML_DOCS/deep-learning/transformers/tutorials/conversational/pyfunc-chat-model.md"
echo "# stub" > "$CML_DOCS/deep-learning/transformers/tutorials/fine-tuning/transformers-fine-tuning.md"
echo "# stub" > "$CML_DOCS/deep-learning/transformers/tutorials/fine-tuning/transformers-peft.md"
echo "# stub" > "$CML_DOCS/deep-learning/transformers/tutorials/audio-transcription/whisper.md"
# These two have the same name as their parent directory, which makes Docusaurus treat them
# as folder index pages (mapped to /prompt-templating/ and /text-generation/ respectively).
# Use a different filename with an explicit slug to create the correct /prompt-templating/prompt-templating
# and /text-generation/text-generation routes that the redirect targets expect.
printf -- '---\nslug: prompt-templating\n---\n# stub\n' > "$CML_DOCS/deep-learning/transformers/tutorials/prompt-templating/stub-content.md"
printf -- '---\nslug: text-generation\n---\n# stub\n' > "$CML_DOCS/deep-learning/transformers/tutorials/text-generation/stub-content.md"
echo "# stub" > "$CML_DOCS/deep-learning/transformers/tutorials/translation/component-translation.md"
echo "# stub" > "$CML_DOCS/deep-learning/sentence-transformers/tutorials/quickstart/sentence-transformers-quickstart.md"
echo "# stub" > "$CML_DOCS/deep-learning/sentence-transformers/tutorials/semantic-similarity/semantic-similarity-sentence-transformers.md"
echo "# stub" > "$CML_DOCS/deep-learning/sentence-transformers/tutorials/semantic-search/semantic-search-sentence-transformers.md"
echo "# stub" > "$CML_DOCS/deep-learning/sentence-transformers/tutorials/paraphrase-mining/paraphrase-mining-sentence-transformers.md"

echo "[DONE] Repository is ready for docusaurus commands."
